/// <summary>
/// Contains constants related to rate limiting.
/// </summary>
public static class RateLimitConst
{
    /// <summary>
    /// Default fixed-window policy for general API endpoints (10 requests per 20 seconds).
    /// </summary>
    public const string RateFix = "RateFix";

    /// <summary>
    /// Relaxed fixed-window policy for chat endpoints (60 requests per 20 seconds).
    /// </summary>
    public const string ChatRead = "ChatRead";
}

using Application.ResultPattern;

namespace Api.Extentions;

/// <summary>
/// Maps <see cref="Result"/> failures to HTTP responses with status codes aligned to <see cref="ErrorType"/>.
/// </summary>
public static class ResultEndpointExtensions
{
    /// <summary>
    /// Returns 200 OK on success, or a Problem response with the correct status code on failure.
    /// </summary>
    /// <param name="result">The command or query result.</param>
    /// <returns>An HTTP result for minimal API endpoints.</returns>
    public static IResult ToHttpResult(this Result result)
    {
        if (result.IsSuccess)
            return Results.Ok();

        return Results.Problem(
            result.Error!.Description,
            statusCode: MapStatusCode(result.Error));
    }

    /// <summary>
    /// Returns 200 OK with the value on success, or a Problem response with the correct status code on failure.
    /// </summary>
    /// <typeparam name="T">The success payload type.</typeparam>
    /// <param name="result">The command or query result.</param>
    /// <returns>An HTTP result for minimal API endpoints.</returns>
    public static IResult ToHttpResult<T>(this Result<T> result)
    {
        if (result.IsSuccess)
            return Results.Ok(result.Value);

        return Results.Problem(
            result.Error!.Description,
            statusCode: MapStatusCode(result.Error));
    }

    private static int MapStatusCode(Error error) => error.ErrorType switch
    {
        ErrorType.NotFound => StatusCodes.Status404NotFound,
        ErrorType.Validation => StatusCodes.Status400BadRequest,
        ErrorType.Conflict => StatusCodes.Status409Conflict,
        ErrorType.UnauthorizedAccess => StatusCodes.Status401Unauthorized,
        ErrorType.AccessForbidden => StatusCodes.Status403Forbidden,
        ErrorType.Failure => StatusCodes.Status500InternalServerError,
        _ => StatusCodes.Status400BadRequest
    };
}

using Api.Constants;
using Microsoft.AspNetCore.RateLimiting;
using System.Threading.RateLimiting;

namespace Api.Extentions;

/// <summary>
/// Provides extension methods for configuring rate limiting.
/// </summary>
public static class RateLimitExtensions
{
    /// <summary>
    /// Adds rate limiting services and policies to the service collection.
    /// </summary>
    /// <param name="services">The service collection to add services to.</param>
    /// <returns>The updated service collection.</returns>
    public static IServiceCollection AddRateLimit(this IServiceCollection services)
    {
        services.AddRateLimiter(options =>
        {
            options.RejectionStatusCode = StatusCodes.Status429TooManyRequests;
            options.OnRejected = async (context, cancellationToken) =>
            {
                int retryAfterSeconds = 20;
                if (context.Lease.TryGetMetadata(MetadataName.RetryAfter, out var retryAfter))
                    retryAfterSeconds = Math.Max(1, (int)Math.Ceiling(retryAfter.TotalSeconds));

                context.HttpContext.Response.StatusCode = StatusCodes.Status429TooManyRequests;
                await context.HttpContext.Response.WriteAsJsonAsync(new
                {
                    error = "TooManyRequests",
                    message = "تعداد درخواست‌ها زیاد است. چند ثانیه صبر کنید.",
                    retryAfter = retryAfterSeconds
                }, cancellationToken);
            };

            options.AddFixedWindowLimiter(policyName: RateLimitConst.RateFix, limiterOptions =>
            {
                limiterOptions.PermitLimit = 10;
                limiterOptions.Window = TimeSpan.FromSeconds(20);
                limiterOptions.QueueProcessingOrder = QueueProcessingOrder.OldestFirst;
                limiterOptions.QueueLimit = 3;
            });

            options.AddFixedWindowLimiter(policyName: RateLimitConst.ChatRead, limiterOptions =>
            {
                limiterOptions.PermitLimit = 60;
                limiterOptions.Window = TimeSpan.FromSeconds(20);
                limiterOptions.QueueProcessingOrder = QueueProcessingOrder.OldestFirst;
                limiterOptions.QueueLimit = 10;
            });
        });

        return services;
    }
}

